import{_ as t,a as e,b as d,c as n,d as s,e as i}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as p,o,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"IP-геолокація та керування користувачами","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/ip-geolocation-and-user-management.md","filePath":"uk-UA/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"uk-UA/Other/ip-geolocation-and-user-management.md"};function h(u,a,g,m,b,P){return o(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="ip-геолокація-та-керування-користувачами" tabindex="-1">IP-геолокація та керування користувачами <a class="header-anchor" href="#ip-геолокація-та-керування-користувачами" aria-label="Permalink to &quot;IP-геолокація та керування користувачами&quot;">​</a></h1><p>IP-геолокація перетворює IP-адреси в записах завантажень, пристроях входу та схожих журналах на приблизні локації.</p><p>Після налаштування адмін-панель може чіткіше показувати, звідки йдуть завантаження та доступи. User Management також дозволяє блокувати або відновлювати доступ до завантаження для підозрілих IP-адрес.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+t+`" alt="IP-геолокація" loading="lazy"></p><h2 id="доступні-налаштування" tabindex="-1">Доступні налаштування <a class="header-anchor" href="#доступні-налаштування" aria-label="Permalink to &quot;Доступні налаштування&quot;">​</a></h2><p>Новіший процес IP geolocation підтримує кілька джерел, а не залежить від одного map service.</p><table tabindex="0"><thead><tr><th>Налаштування</th><th>Призначення</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Вибирає мову відображення: English, Simplified Chinese, Japanese, French тощо.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind для MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Ключ Tencent Location Service. Корисний для китайських адрес і IP материкового Китаю.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Підтримує багатомовну IP-геолокацію.</td></tr></tbody></table><p>Заповнюйте тільки ті сервіси, які потрібні. Немає потреби налаштовувати кожне поле.</p><p>Якщо ключів немає, ImgBed усе одно спробує вбудовані безплатні джерела, але стабільність, підтримка мов і точність можуть бути нижчими, ніж у сервісу, який ви налаштуєте самі.</p><h2 id="рекомендовании-вибір" tabindex="-1">Рекомендований вибір <a class="header-anchor" href="#рекомендовании-вибір" aria-label="Permalink to &quot;Рекомендований вибір&quot;">​</a></h2><p>Якщо переважно потрібні китайські адреси:</p><ol><li>Встановіть IP geolocation language як Simplified Chinese.</li><li>Налаштуйте Tencent Map Key.</li><li>За бажанням додайте MaxMind або ipapi як fallback sources.</li></ol><p>Якщо потрібні англійські або багатомовні адреси:</p><ol><li>Виберіть потрібну мову.</li><li>Налаштуйте MaxMind Account ID і License Key.</li><li>Додайте ipapi Key, якщо потрібні кращі багатомовні результати.</li></ol><h2 id="налаштування-maxmind" tabindex="-1">Налаштування MaxMind <a class="header-anchor" href="#налаштування-maxmind" aria-label="Permalink to &quot;Налаштування MaxMind&quot;">​</a></h2><p>MaxMind потребує:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Знайдіть account ID у dashboard MaxMind і згенеруйте License Key на сторінці License Keys.</p><p><img src="`+e+'" alt="Налаштування MaxMind key" loading="lazy"></p><p>Після генерації вставте Account ID і License Key в ImgBed та збережіть.</p><p>Безплатний план MaxMind підходить для щоденного використання, але має request limits. Якщо квоту вичерпано, ImgBed продовжить пробувати інші доступні джерела.</p><h2 id="налаштування-ipapi" tabindex="-1">Налаштування ipapi <a class="header-anchor" href="#налаштування-ipapi" aria-label="Permalink to &quot;Налаштування ipapi&quot;">​</a></h2><p>ipapi використовує APILayer API Key.</p><p>Відкрийте консоль ipapi й скопіюйте API Key, який там показано.</p><p><img src="'+d+'" alt="Налаштування ipapi" loading="lazy"></p><p>Вставте його в поле <code>ipapi Key</code> в ImgBed і збережіть.</p><p>ipapi підтримує багатомовну IP-геолокацію й корисний, коли адреси треба показувати вибраною мовою. Його безплатний план також має request limits. Якщо квота закінчиться, ImgBed продовжить пробувати інші доступні джерела.</p><h2 id="налаштування-tencent-map-key" tabindex="-1">Налаштування Tencent Map Key <a class="header-anchor" href="#налаштування-tencent-map-key" aria-label="Permalink to &quot;Налаштування Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key корисний для китайських адрес, особливо IP материкового Китаю.</p><p>Під час створення key у Tencent Location Service увімкніть:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Після створення вставте key у <code>Tencent Map Key</code> і збережіть.</p><p>Якщо вам потрібна тільки базова китайська IP-геолокація, Tencent Map Key достатньо для старту.</p><h2 id="що-перевіряти-в-user-management" tabindex="-1">Що перевіряти в User Management <a class="header-anchor" href="#що-перевіряти-в-user-management" aria-label="Permalink to &quot;Що перевіряти в User Management&quot;">​</a></h2><p>User Management доступний у верхній частині адмін-панелі.</p><p><img src="'+n+'" alt="User management" loading="lazy"></p><p>User Management показує активність завантажень за IP:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Опис</th></tr></thead><tbody><tr><td>IP source</td><td>IP-адреса джерела завантаження.</td></tr><tr><td>Address</td><td>Приблизна локація, визначена за IP.</td></tr><tr><td>Total upload size</td><td>Загальний розмір файлів, завантажених із цього IP.</td></tr><tr><td>Upload count</td><td>Кількість завантажень із цього IP.</td></tr><tr><td>Upload allowed</td><td>Увімкнено — завантаження дозволені. Вимкнено — завантаження заблоковані.</td></tr></tbody></table><p>Натисніть стрілку ліворуч, щоб розгорнути список файлів, завантажених із цього IP.</p><p>У списку файлів показуються назва файлу, preview, розмір, moderation result, статус файлу та час завантаження. Якщо завантаження виглядають підозріло, спершу розгорніть IP, перегляньте файли, а потім вирішіть, чи блокувати подальші завантаження.</p><p>Якщо IP підозрілий, вимкніть <code>Upload allowed</code>. Майбутні завантаження з цього IP будуть заблоковані.</p><h2 id="пошук-сортування-та-розширені-фільтри" tabindex="-1">Пошук, сортування та розширені фільтри <a class="header-anchor" href="#пошук-сортування-та-розширені-фільтри" aria-label="Permalink to &quot;Пошук, сортування та розширені фільтри&quot;">​</a></h2><p>Угорі User Management можна шукати за IP source або address.</p><p>Сортуйте за часом, upload count або total upload size, щоб знайти нещодавніх авторів завантажень, часті завантаження або IP з великим використанням.</p><p>Для глибшої перевірки відкрийте advanced filters.</p><p><img src="'+s+'" alt="Розширені фільтри" loading="lazy"></p><p>Advanced filters підтримують:</p><table tabindex="0"><thead><tr><th>Фільтр</th><th>Використання</th></tr></thead><tbody><tr><td>Time range</td><td>Показати IP, які завантажували файли у вибраний період.</td></tr><tr><td>Access status</td><td>Фільтр за normal, blocked та схожими станами.</td></tr><tr><td>Allow/block list</td><td>Фільтр за allowlist, blocklist або unset.</td></tr><tr><td>File type</td><td>Показати IP, які завантажували images, videos, audio, documents, code або інші файли.</td></tr><tr><td>File size</td><td>Фільтр за діапазоном розміру завантажених файлів.</td></tr><tr><td>Age rating</td><td>Фільтр за unset, General, R12+, R16+, R18 та схожими рейтингами.</td></tr><tr><td>File status</td><td>Фільтр за поточним статусом файлу для розслідування аномалій.</td></tr></tbody></table><p>Натисніть <code>Apply Filters</code>, щоб застосувати. <code>Reset</code> повертає всі дані.</p><h2 id="мобільнии-вигляд" tabindex="-1">Мобільний вигляд <a class="header-anchor" href="#мобільнии-вигляд" aria-label="Permalink to &quot;Мобільний вигляд&quot;">​</a></h2><p>На мобільних пристроях User Management переходить у картковий layout.</p><p><img src="'+i+`" alt="Мобільний User Management" loading="lazy"></p><p>Кожна картка показує IP, address, total upload size, upload count і перемикач upload allowed. Користувачами можна керувати без горизонтального прокручування таблиці.</p><h2 id="якщо-локація-виглядає-неправильно" tabindex="-1">Якщо локація виглядає неправильно <a class="header-anchor" href="#якщо-локація-виглядає-неправильно" aria-label="Permalink to &quot;Якщо локація виглядає неправильно&quot;">​</a></h2><p>IP-геолокація приблизна. Це не точна адреса до вулиці чи будинку.</p><p>Якщо користувач за proxy, data center, cloud server або cross-border network, показана локація може відрізнятися від реальної.</p><p>Використовуйте цю функцію, щоб розуміти приблизне походження, знаходити аномальні завантаження й допомагати з рішеннями про блокування. Не сприймайте її як точне відстеження.</p><h2 id="типові-випадки" tabindex="-1">Типові випадки <a class="header-anchor" href="#типові-випадки" aria-label="Permalink to &quot;Типові випадки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Випадок</th><th>Значення</th></tr></thead><tbody><tr><td>Address порожній</td><td>IP ще міг не визначитися або поточне джерело тимчасово недоступне.</td></tr><tr><td>Мова address неправильна</td><td>Перевірте IP geolocation language і чи налаштовано джерело з підтримкою цієї мови.</td></tr><tr><td>Address показує data center</td><td>Багато proxy, cloud servers і crawlers відображаються як data center або ISP addresses.</td></tr><tr><td>Upload count високий</td><td>Уважно перевірте цей IP і за потреби заблокуйте завантаження.</td></tr><tr><td>Total upload size великий</td><td>Відсортуйте або відфільтруйте, розгорніть IP і перегляньте конкретні файли.</td></tr><tr><td>Потрібно відновити після блокування</td><td>Увімкніть <code>Upload allowed</code> назад.</td></tr></tbody></table><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити IP Geolocation в Other Settings</span></span>
<span class="line"><span>-&gt; Вибрати IP geolocation language</span></span>
<span class="line"><span>-&gt; За потреби заповнити MaxMind, Tencent Map або ipapi credentials</span></span>
<span class="line"><span>-&gt; Зберегти налаштування</span></span>
<span class="line"><span>-&gt; Відкрити User Management</span></span>
<span class="line"><span>-&gt; Переглянути IP source, address, total upload size і upload count</span></span>
<span class="line"><span>-&gt; Використати search, sort або advanced filters для пошуку аномальних IP</span></span>
<span class="line"><span>-&gt; Дозволити або заблокувати завантаження за потреби</span></span></code></pre></div>`,64)])])}const M=p(c,[["render",h]]);export{x as __pageData,M as default};
